# test_app.py

import unittest
from app import app, calculate  # Importa la función calculate desde el archivo app.py

class TestBackend(unittest.TestCase):

    def setUp(self):
        self.app = app.test_client()

    def test_addition(self):
        response = self.app.post('/calculate', json={'operation': 'add', 'num1': 5, 'num2': 3})
        self.assertEqual(response.status_code, 200)
        self.assertEqual(response.json['result'], 8)

    def test_subtraction(self):
        response = self.app.post('/calculate', json={'operation': 'subtract', 'num1': 10, 'num2': 5})
        self.assertEqual(response.status_code, 200)
        self.assertEqual(response.json['result'], 5)

    def test_multiplication(self):
        response = self.app.post('/calculate', json={'operation': 'multiply', 'num1': 4, 'num2': 6})
        self.assertEqual(response.status_code, 200)
        self.assertEqual(response.json['result'], 24)

    def test_division(self):
        response = self.app.post('/calculate', json={'operation': 'divide', 'num1': 8, 'num2': 2})
        self.assertEqual(response.status_code, 200)
        self.assertEqual(response.json['result'], 4)

if __name__ == '__main__':
    unittest.main()
