2. **models.py**
```python
from sqlite3 import connect

class Turno:
    def __init__(self, id_turno, fecha_hora_inicio, fecha_hora_fin):
        self.id_turno = id_turno
        self.fecha_hora_inicio = fecha_hora_inicio
        self.fecha_hora_fin = fecha_hora_fin

def get_turnos():
    conn = connect('turnos.db')
    cursor = conn.cursor()
    cursor.execute("SELECT * FROM turnos")
    rows = cursor.fetchall()
    conn.close()

    return [Turno(row[0], row[1], row[2]) for row in rows]

def add_turno(turno):
    conn = connect('turnos.db')
    cursor = conn.cursor()
    cursor.execute("INSERT INTO turnos (fecha_hora_inicio, fecha_hora_fin) VALUES (?, ?)", 
                   (turno.fecha_hora_inicio.strftime('%Y-%m-%d %H:%M'), turno.fecha_hora_fin.strftime('%Y-%m-%d %H:%M')))
    conn.commit()
    conn.close()

def delete_turno(id_turno):
    conn = connect('turnos.db')
    cursor = conn.cursor()
    cursor.execute("DELETE FROM turnos WHERE id_turno=?", (id_turno,))
    conn.commit()
    conn.close()
```

3. **routes.py**
```python
from flask import Blueprint, request

from .models import get_turnos, add_turno, delete_turno

turnos_bp = Blueprint('turnos', __name__)

@turnos_bp.route('/api/turnos', methods=['GET'])
def get_all_turnos():
    return {'turnos': [t.to_dict() for t in get_turnos()]}

@turnos_bp.route('/api/turnos', methods=['POST'])
def add_new_turno():
    data = request.get_json()
    new_turno = Turno(id_turno=len(get_turnos()) + 1, 
                      fecha_hora_inicio=data['fecha_hora_inicio'], 
                      fecha_hora_fin=data['fecha_hora_fin'])
    add_turno(new_turno)
    return {'message': 'Turno agregado'}

@turnos_bp.route('/api/turnos/<int:id>', methods=['DELETE'])
def delete_turno_by_id(id):
    delete_turno(id)
    return {'message': f'Turno con id {id} eliminado'}
```

4. **main.py**
