### Archivo: templates/app.js
```javascript
document.addEventListener("DOMContentLoaded", function() {
    const turnosDiv = document.getElementById('turnos');

    // Simulación de la API para obtener los turnos
    axios.get('/api/turnos')
        .then(response => {
            const turnos = response.data;
            renderTurnos(turnos);
        })
        .catch(error => {
            console.error("Error al obtener los turnos:", error);
        });
});

function renderTurnos(turnos) {
    let html = '<ul>';
    for (let turno of turnos) {
        html += `<li>${turno.fecha} - ${turno.hora} - ${empleados[turno.empleado].nombre}</li>`;
    }
    html += '</ul>';
    document.getElementById('turnos').innerHTML = html;
}
