### server.js

```javascript
const express = require('express');
const app = express();
const sqlite3 = require('sqlite3').verbose();

// Configuración de la base de datos SQLite
const db = new sqlite3.Database(':memory:', err => {
    if (err) {
        return console.error(err.message);
    }
});

// Crear las tablas en la base de datos SQLite
db.run(`
CREATE TABLE IF NOT EXISTS Productos (
  id_producto INTEGER PRIMARY KEY AUTOINCREMENT,
  nombre TEXT NOT NULL,
  precio REAL NOT NULL,
  stock INTEGER DEFAULT 0
)`, err => {
    if (err) return console.error(err.message);
});

db.run(`
CREATE TABLE IF NOT EXISTS Clientes (
  id_cliente INTEGER PRIMARY KEY AUTOINCREMENT,
  nombre TEXT NOT NULL,
  telefono TEXT,
  correo_electrónico TEXT CHECK(correo_electrónico LIKE '%@%')
)`, err => {
    if (err) return console.error(err.message);
});

db.run(`
CREATE TABLE IF NOT EXISTS Ventas (
  id_venta INTEGER PRIMARY KEY AUTOINCREMENT,
  fecha_hora DATETIME DEFAULT CURRENT_TIMESTAMP,
  id_cliente INTEGER,
  total REAL,
  FOREIGN KEY(id_cliente) REFERENCES Clientes(id_cliente)
)`, err => {
    if (err) return console.error(err.message);
});

db.run(`
CREATE TABLE IF NOT EXISTS Detalle_Venta (
  id_detalle INTEGER PRIMARY KEY AUTOINCREMENT,
  id_venta INTEGER,
  id_producto INTEGER,
  cantidad INTEGER DEFAULT 1,
  precio_unitario REAL,
  FOREIGN KEY(id_venta) REFERENCES Ventas(id_venta),
  FOREIGN KEY(id_producto) REFERENCES Productos(id_producto)
)`, err => {
    if (err) return console.error(err.message);
});

// Middleware para manejar los encabezados de respuesta
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// Rutas del backend

// GET /productos
app.get('/productos', async (req, res) => {
    const productos = await db.all('SELECT * FROM Productos');
    res.send(productos);
});

// POST /productos
app.post('/productos', async (req, res) => {
    try {
        const { nombre, precio } = req.body;
        if (!nombre || !precio) throw new Error("Nombre y precio son obligatorios");

        await db.run('INSERT INTO Productos(nombre, precio) VALUES (?, ?)', [nombre, precio]);
        res.send({ message: 'Producto agregado' });
    } catch (error) {
        res.status(400).send(error.message);
    }
});

// PUT /productos/{id}
app.put('/productos/:id', async (req, res) => {
    try {
        const { id } = req.params;
        const { nombre, precio } = req.body;

        if (!nombre || !precio) throw new Error("Nombre y precio son obligatorios");

        await db.run('UPDATE Productos SET nombre = ?, precio = ? WHERE id_producto = ?', [nombre, precio, parseInt(id)]);
        res.send({ message: 'Producto actualizado' });
