  const Turno = require('../models/Turno');

  // Crear un turno
  router.post('/', async (req, res) => {
      try {
          const nuevoTurno = new Turno(req.body);
          await nuevoTurno.save();
          res.status(201).json(nuevoTurno);
      } catch (error) {
          res.status(400).json({ message: error.message });
      }
  });

  // Obtener todos los turnos
  router.get('/', async (req, res) => {
      try {
          const turnos = await Turno.find();
          res.json(turnos);
      } catch (error) {
          res.status(500).json({ message: error.message });
      }
  });

  // Obtener un turno por ID
  router.get('/:id', async (req, res) => {
      try {
          const turno = await Turno.findById(req.params.id);
          if (!turno) return res.status(404).json({ message: 'Turno no encontrado' });
          res.json(turno);
      } catch (error) {
          res.status(500).json({ message: error.message });
      }
  });

  // Actualizar un turno
  router.put('/:id', async (req, res) => {
      try {
          const updatedTurno = await Turno.findByIdAndUpdate(req.params.id, req.body, { new: true });
          if (!updatedTurno) return res.status(404).json({ message: 'Turno no encontrado' });
          res.json(updatedTurno);
      } catch (error) {
          res.status(500).json({ message: error.message });
      }
  });

  // Eliminar un turno
  router.delete('/:id', async (req, res) => {
      try {
          const borrado = await Turno.findByIdAndDelete(req.params.id);
          if (!borrado) return res.status(404).json({ message: 'Turno no encontrado' });
          res.json({ message: 'Turno eliminado' });
      } catch (error) {
          res.status(500).json({ message: error.message });
      }
  });

  module.exports = router;
