  const app = Vue.createApp({
      data() {
          return {
              turnos: [],
              nuevoTurno: {},
              empleado: '',
              fecha: new Date(),
              horaInicio: '08:00',
              horaFin: '17:00'
          };
      },
      methods: {
          async getTurnos() {
              try {
                  const response = await fetch('/api/turnos');
                  this.turnos = await response.json();
              } catch (error) {
                  console.error(error);
              }
          },
          async createTurno() {
              const turnoData = {
                  empleado: this.empleado,
                  fecha: this.fecha.toISOString().split('T')[0],
                  horaInicio: this.horaInicio,
                  horaFin: this.horaFin
              };

              try {
                  await fetch('/api/turnos', {
                      method: 'POST',
                      headers: { 'Content-Type': 'application/json' },
                      body: JSON.stringify(turnoData)
                  });
                  alert('Turno creado exitosamente');
                  this.getTurnos();
              } catch (error) {
                  console.error(error);
              }
          },
          async updateTurno(id, turnoData) {
              try {
                  await fetch(`/api/turnos/${id}`, {
                      method: 'PUT',
                      headers: { 'Content-Type': 'application/json' },
                      body: JSON.stringify(turnoData)
                  });
                  alert('Turno actualizado exitosamente');
                  this.getTurnos();
              } catch (error) {
                  console.error(error);
              }
          },
          async deleteTurno(id) {
              try {
                  await fetch(`/api/turnos/${id}`, { method: 'DELETE' });
                  alert('Turno eliminado exitosamente');
                  this.getTurnos();
              } catch (error) {
                  console.error(error);
              }
          }
      },
      created() {
          this.getTurnos();
      }
  });

  app.mount('#app');
  ```

