Para completar el backend de esta aplicación, necesitamos crear varios archivos que serán fundamentales para la lógica del servidor y las rutas necesarias para manejar las peticiones HTTP. Aquí te presento cómo puedes estructurar tu proyecto y los archivos necesarios:

### Archivo: `config.js`
Este archivo contiene la configuración de conexión a la base de datos MongoDB.

```javascript
// config.js

const mongoose = require('mongoose');

// Configuración de conexión con MongoDB
const connectDB = async () => {
  try {
    const conn = await mongoose.connect(process.env.DB_URI, {
      useNewUrlParser: true,
      useUnifiedTopology: true,
    });

    console.log(`MongoDB Connected: ${conn.connection.host}`);
  } catch (error) {
    console.error(`Error connecting to MongoDB: ${error.message}`);
    process.exit(1);
  }
};

module.exports = connectDB;
```

### Archivo: `auth.js`
Este archivo contiene las funciones para manejar el registro y login de los usuarios.

```javascript
// auth.js

const bcryptjs = require('bcryptjs');
const jwt = require('jsonwebtoken');

const User = require('./models/User');

exports.signup = async (req, res) => {
  try {
    // Verificar si el usuario ya existe
    const userExists = await User.findOne({ username: req.body.username });

    if (userExists) {
      return res.status(409).json({ message: 'El nombre de usuario ya existe' });
    }

    // Hash la contraseña
    const hashedPassword = await bcryptjs.hash(req.body.password, 8);

    // Crear un nuevo usuario en la base de datos
    const user = new User({
      username: req.body.username,
      password: hashedPassword,
    });

    await user.save();

    res.status(201).json({ message: 'Usuario creado exitosamente', data: user });
  } catch (error) {
    console.error(error);
    res.status(500).json({ message: 'Error interno del servidor' });
  }
};

exports.login = async (req, res) => {
  try {
    const { username, password } = req.body;

    // Verificar si el usuario existe
    const user = await User.findOne({ username });

    if (!user) {
      return res.status(401).json({ message: 'El nombre de usuario no existe' });
    }

    // Verificar la contraseña
    const isMatch = await bcryptjs.compare(password, user.password);

    if (!isMatch) {
      return res.status(401).json({ message: 'Contraseña incorrecta' });
    }

    // Crear un token JWT
    const token = jwt.sign({ id: user._id }, process.env.JWT_SECRET_KEY || 'default-secret-key', { expiresIn: '365d' });

    res.json({ message: 'Inicio de sesión exitoso', data: { username, token } });
  } catch (error) {
    console.error(error);
    res.status(500).json({ message: 'Error interno del servidor' });
  }
};
```

